const raw = $json.body ?? $json;

const ACTIONS = new Set(['deploy', 'restart', 'status', 'stop', 'logs']);

function value(name, fallback) {
  const v = raw[name];
  if (v === undefined || v === null || String(v).trim() === '') return fallback;
  return String(v).trim();
}

function shellQuote(v) {
  return `'${String(v).replace(/'/g, `'\\''`)}'`;
}

function safePath(v) {
  return /^\/[A-Za-z0-9._\-\/]+$/.test(v) && !v.includes('..');
}

function safeRef(v) {
  return /^[A-Za-z0-9._\/-]+$/.test(v) && !v.startsWith('-') && !v.includes('..');
}

function safeHost(v) {
  return /^[A-Za-z0-9._:-]+$/.test(v);
}

const action = value('action', 'deploy').toLowerCase();
const repoUrl = value('repo_url', 'git@github.com:chenjiuxuan1/ZNZB.git');
const branch = value('branch', 'codex-show-scanned-dashboards');
const deployDir = value('deploy_dir', '/root/ZNZB');
const host = value('host', '0.0.0.0');
const port = Number(value('port', '8787'));
const lines = Math.max(20, Math.min(500, Number(value('lines', '120')) || 120));
const requestId = value('request_id', `duty-deploy-${Date.now()}`);

const errors = [];
if (!ACTIONS.has(action)) errors.push(`unsupported action: ${action}`);
if (!safePath(deployDir)) errors.push('deploy_dir must be an absolute safe path, for example /root/ZNZB');
if (!safeRef(branch)) errors.push('branch contains unsafe characters');
if (!safeHost(host)) errors.push('host contains unsafe characters');
if (!Number.isInteger(port) || port < 1 || port > 65535) errors.push('port must be 1-65535');
if (['deploy', 'restart'].includes(action) && !repoUrl) errors.push('repo_url is required');

const q = {
  action: shellQuote(action),
  repoUrl: shellQuote(repoUrl),
  branch: shellQuote(branch),
  deployDir: shellQuote(deployDir),
  host: shellQuote(host),
  port: shellQuote(String(port)),
  lines: shellQuote(String(lines)),
};

const common = `set -euo pipefail\nACTION=${q.action}\nREPO_URL=${q.repoUrl}\nBRANCH=${q.branch}\nDEPLOY_DIR=${q.deployDir}\nHOST_VALUE=${q.host}\nPORT_VALUE=${q.port}\nLOG_LINES=${q.lines}\nPID_FILE="$DEPLOY_DIR/platform.pid"\nLOG_FILE="$DEPLOY_DIR/platform.log"\ncd_or_create_parent() { mkdir -p "$(dirname \"$DEPLOY_DIR\")"; }\nstop_existing() { if [ -f "$PID_FILE" ] && kill -0 "$(cat \"$PID_FILE\")" 2>/dev/null; then echo "[stop] stopping pid $(cat \"$PID_FILE\")"; kill "$(cat \"$PID_FILE\")" || true; sleep 2; fi; }\nstart_platform() { cd "$DEPLOY_DIR"; echo "[start] HOST=$HOST_VALUE PORT=$PORT_VALUE npm run platform"; HOST="$HOST_VALUE" PORT="$PORT_VALUE" nohup npm run platform > "$LOG_FILE" 2>&1 & echo $! > "$PID_FILE"; sleep 3; if kill -0 "$(cat \"$PID_FILE\")" 2>/dev/null; then echo "[ok] running pid $(cat \"$PID_FILE\")"; echo "[ok] url http://127.0.0.1:$PORT_VALUE/#/wattrel-alerts"; else echo "[error] platform exited during startup"; tail -n 80 "$LOG_FILE" || true; exit 1; fi; }\nstatus_platform() { if [ -f "$PID_FILE" ] && kill -0 "$(cat \"$PID_FILE\")" 2>/dev/null; then echo "[status] running pid $(cat \"$PID_FILE\")"; else echo "[status] stopped"; fi; if [ -f "$LOG_FILE" ]; then echo "[log-tail]"; tail -n 40 "$LOG_FILE" || true; fi; }\n`;

let body = '';
if (action === 'deploy') {
  body = `echo "[deploy] request ${requestId}"\ncd_or_create_parent\nif [ ! -d "$DEPLOY_DIR/.git" ]; then echo "[clone] $REPO_URL -> $DEPLOY_DIR"; git clone --branch "$BRANCH" "$REPO_URL" "$DEPLOY_DIR"; fi\ncd "$DEPLOY_DIR"\necho "[git] fetch origin $BRANCH"\ngit fetch origin "$BRANCH"\ngit checkout "$BRANCH"\ngit reset --hard "origin/$BRANCH"\necho "[npm] install"\nnpm install\ncp -n config/wattrel.config.example.json config/wattrel.config.json 2>/dev/null || true\nstop_existing\nstart_platform\n`;
} else if (action === 'restart') {
  body = `echo "[restart] request ${requestId}"\nif [ ! -d "$DEPLOY_DIR" ]; then echo "[error] deploy_dir not found: $DEPLOY_DIR"; exit 1; fi\nstop_existing\nstart_platform\n`;
} else if (action === 'status') {
  body = `echo "[status] request ${requestId}"\nstatus_platform\n`;
} else if (action === 'stop') {
  body = `echo "[stop] request ${requestId}"\nstop_existing\nstatus_platform\n`;
} else if (action === 'logs') {
  body = `echo "[logs] request ${requestId}"\nif [ -f "$LOG_FILE" ]; then tail -n "$LOG_LINES" "$LOG_FILE"; else echo "[logs] log file not found: $LOG_FILE"; fi\n`;
}

return [{
  json: {
    valid: errors.length === 0,
    errors,
    request_id: requestId,
    action,
    repo_url: repoUrl,
    branch,
    deploy_dir: deployDir,
    host,
    port,
    platform_url: `http://127.0.0.1:${port}/#/wattrel-alerts`,
    command: `bash -lc ${shellQuote(common + body)}`,
  },
}];

const raw = $json;
const stdout = typeof raw.stdout === 'string' ? raw.stdout.trim() : '';
const stderr = typeof raw.stderr === 'string' ? raw.stderr.trim() : '';
const exitCode = raw.code ?? raw.exitCode ?? 0;
return [{
  json: {
    success: Number(exitCode) === 0,
    exit_code: exitCode,
    stdout,
    stderr,
  },
}];
